const item = $input.first();

if (!item.binary || !item.binary.data) {
  throw new Error('No se encontró la fotografía binaria.');
}

const token = `${Date.now().toString(36)}${Math.random().toString(36).slice(2, 8)}`;

return [{
  json: {
    token,
    chat_id: $('Telegram Trigger').first().json.message.chat.id,
    telegram_message_id: $('Telegram Trigger').first().json.message.message_id
  },
  binary: item.binary
}];

const upload = $json;
const original = $('Preparar imagen').first().json;

if (!upload?.name) {
  throw new Error('ComfyUI no devolvió el nombre de la imagen subida.');
}

const store = $getWorkflowStaticData('global');
store.jobs ??= {};

const now = Date.now();
const maxAge = 24 * 60 * 60 * 1000;

// Limpiar solicitudes antiguas
for (const [key, value] of Object.entries(store.jobs)) {
  if (!value?.created_at || now - value.created_at > maxAge) {
    delete store.jobs[key];
  }
}

store.jobs[original.token] = {
  filename: upload.name,
  subfolder: upload.subfolder || '',
  type: upload.type || 'input',
  chat_id: original.chat_id,
  created_at: now
};

return [{
  json: {
    token: original.token,
    chat_id: original.chat_id,
    filename: upload.name
  }
}];

const query = $json.callback_query;

if (!query) {
  throw new Error('No se recibió callback_query.');
}

const raw = String(query.data || '');
const [motor, token] = raw.split(':');

const result = {
  valid: false,
  motor,
  token,
  callback_query_id: query.id,
  chat_id: query.message?.chat?.id,
  selection_message_id: query.message?.message_id,
  notice: 'La solicitud ya no está disponible. Envía de nuevo la fotografía.'
};

if (!['openai', 'local'].includes(motor) || !token) {
  return [{ json: result }];
}

const store = $getWorkflowStaticData('global');
store.jobs ??= {};
const job = store.jobs[token];

if (!job || Number(job.chat_id) !== Number(result.chat_id)) {
  return [{ json: result }];
}

// Consumir la solicitud para evitar dobles ejecuciones
delete store.jobs[token];

return [{
  json: {
    ...result,
    valid: true,
    filename: job.filename,
    subfolder: job.subfolder || '',
    type: job.type || 'input',
    notice: motor === 'local'
      ? 'Procesando con HERCULES local…'
      : 'Procesando con OpenAI…'
  }
}];

const response = $json;

if (response.error) {
  throw new Error(response.error.message || 'OpenAI no pudo generar la imagen');
}

const base64 = response?.data?.[0]?.b64_json;

if (!base64) {
  throw new Error('La respuesta de OpenAI no contiene data[0].b64_json');
}

return [{
  json: {
    ok: true,
    chat_id: $('Procesar selección').first().json.chat_id
  },
  binary: {
    data: {
      data: base64,
      mimeType: 'image/png',
      fileName: 'caricatura_openai.png'
    }
  }
}];

const item = $input.first();

if (!item.binary?.data) {
  throw new Error('No se pudo recuperar la imagen original desde ComfyUI.');
}

const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
const selection = $('Procesar selección').first().json;

const ollama_body = {
  model: 'qwen3-vl:8b-instruct',
  stream: false,
  format: 'json',
  keep_alive: 0,
  messages: [
    {
      role: 'user',
      content: "Clasifica únicamente el contenido principal de la imagen.\n\nDevuelve exclusivamente un objeto JSON válido con una sola propiedad:\n\n{\"tipo_sujeto\":\"persona\"}\n\nValores permitidos:\n- \"persona\": una o varias personas son el contenido principal.\n- \"animal\": uno o varios animales son el contenido principal.\n- \"objeto\": el contenido principal es un objeto, máquina, vehículo, escafandra, traje, pieza histórica, obra o elemento técnico sin una persona real como sujeto principal.\n- \"mixto\": aparecen de forma importante sujetos de dos o más categorías anteriores.\n\nNo describas la imagen.\nNo añadas explicaciones.\nNo añadas ninguna otra propiedad.",
      images: [buffer.toString('base64')]
    }
  ],
  options: {
    temperature: 0
  }
};

return [{
  json: {
    ...selection,
    image_base64: buffer.toString('base64'),
    mime_type: item.binary.data.mimeType || 'image/png',
    ollama_body
  },
  binary: item.binary
}];

const positivePrompt = String($json.positive_base || '').trim();
const suppliedNegative = String($json.negative_prompt || '').trim();
const tipo = String($json.tipo_sujeto || 'mixto').toLowerCase().trim();

if (!positivePrompt) {
  throw new Error('Falta el prompt positivo de la categoría seleccionada.');
}

const selection = $('Procesar selección').first().json;
const uploadedName = selection.filename;
const chatId = selection.chat_id;

if (!uploadedName) {
  throw new Error('No se encontró el nombre de la imagen subida a ComfyUI.');
}

const settings = $json.local_settings || {};

const seedMode = settings.seed_mode || 'random';
const fixedSeed = Number(settings.fixed_seed ?? 987654321);

const seed = seedMode === 'fixed'
  ? fixedSeed
  : Math.floor(Math.random() * 2147483647);

const steps = Number(settings.steps ?? 4);
const cfg = Number(settings.cfg ?? 1.0);
const denoise = Number(settings.denoise ?? 1.0);
const loraStrength = Number(settings.lora_strength ?? 1.0);
const modelShift = Number(settings.model_shift ?? 3.1);

const useNegative = settings.use_negative_prompt !== false;
const negativePrompt = useNegative ? suppliedNegative : '';

const workflow = {
  "1": {
    "class_type": "LoadImage",
    "inputs": {
      "image": uploadedName
    },
    "_meta": {
      "title": "Imagen recibida desde Telegram"
    }
  },

  "2": {
    "class_type": "FluxKontextImageScale",
    "inputs": {
      "image": ["1", 0]
    },
    "_meta": {
      "title": "Ajustar imagen"
    }
  },

  "3": {
    "class_type": "UNETLoader",
    "inputs": {
      "unet_name": "qwen_image_edit_2511_bf16.safetensors",
      "weight_dtype": "default"
    },
    "_meta": {
      "title": "Qwen Image Edit 2511"
    }
  },

  "4": {
    "class_type": "ModelSamplingAuraFlow",
    "inputs": {
      "model": ["3", 0],
      "shift": modelShift
    }
  },

  "5": {
    "class_type": "CFGNorm",
    "inputs": {
      "model": ["4", 0],
      "strength": 1.0,
      "pre_cfg": false
    }
  },

  "6": {
    "class_type": "LoraLoaderModelOnly",
    "inputs": {
      "model": ["5", 0],
      "lora_name": "Qwen-Image-Edit-2511-Lightning-4steps-V1.0-bf16.safetensors",
      "strength_model": loraStrength
    }
  },

  "7": {
    "class_type": "CLIPLoader",
    "inputs": {
      "clip_name": "qwen_2.5_vl_7b_fp8_scaled.safetensors",
      "type": "qwen_image",
      "device": "default"
    }
  },

  "8": {
    "class_type": "VAELoader",
    "inputs": {
      "vae_name": "qwen_image_vae.safetensors"
    }
  },

  "9": {
    "class_type": "TextEncodeQwenImageEditPlus",
    "inputs": {
      "clip": ["7", 0],
      "prompt": positivePrompt,
      "vae": ["8", 0],
      "image1": ["2", 0]
    }
  },

  "10": {
    "class_type": "FluxKontextMultiReferenceLatentMethod",
    "inputs": {
      "conditioning": ["9", 0],
      "reference_latents_method": "index_timestep_zero"
    }
  },

  "11": {
    "class_type": "TextEncodeQwenImageEditPlus",
    "inputs": {
      "clip": ["7", 0],
      "prompt": negativePrompt,
      "vae": ["8", 0],
      "image1": ["2", 0]
    }
  },

  "12": {
    "class_type": "FluxKontextMultiReferenceLatentMethod",
    "inputs": {
      "conditioning": ["11", 0],
      "reference_latents_method": "index_timestep_zero"
    }
  },

  "13": {
    "class_type": "VAEEncode",
    "inputs": {
      "pixels": ["2", 0],
      "vae": ["8", 0]
    }
  },

  "14": {
    "class_type": "KSampler",
    "inputs": {
      "model": ["6", 0],
      "positive": ["10", 0],
      "negative": ["12", 0],
      "latent_image": ["13", 0],
      "seed": seed,
      "steps": steps,
      "cfg": cfg,
      "sampler_name": "euler",
      "scheduler": "simple",
      "denoise": denoise
    }
  },

  "15": {
    "class_type": "VAEDecode",
    "inputs": {
      "samples": ["14", 0],
      "vae": ["8", 0]
    }
  },

  "16": {
    "class_type": "SaveImage",
    "inputs": {
      "images": ["15", 0],
      "filename_prefix": `HERCULES_caricatura_${tipo}`
    }
  }
};

return [{
  json: {
    chat_id: chatId,
    tipo_sujeto: tipo,
    clasificacion_ollama: $json.clasificacion_ollama || {},
    positive_prompt: positivePrompt,
    negative_prompt: negativePrompt,
    local_settings: settings,
    seed,
    workflow
  }
}];

const promptId = $json.prompt_id;

if (!promptId) {
  throw new Error('ComfyUI no devolvió prompt_id.');
}

const baseUrl = 'http://HERCULES_IP:8188';
let entry = null;

for (let attempt = 0; attempt < 600; attempt++) {
  await new Promise(resolve => setTimeout(resolve, 3000));

  const history = await this.helpers.httpRequest({
    method: 'GET',
    url: `${baseUrl}/history/${promptId}`,
    json: true,
    timeout: 3000000
  });

  const candidate = history?.[promptId] || history;

  if (candidate?.outputs && Object.keys(candidate.outputs).length > 0) {
    entry = candidate;
    break;
  }
}

if (!entry) {
  throw new Error('ComfyUI no terminó dentro del tiempo de espera.');
}

let imageInfo = null;

for (const output of Object.values(entry.outputs)) {
  if (output?.images?.length) {
    imageInfo = output.images[0];
    break;
  }
}

if (!imageInfo) {
  throw new Error('La ejecución terminó, pero ComfyUI no devolvió ninguna imagen.');
}

return [{
  json: {
    prompt_id: promptId,
    chat_id: $('Procesar selección').first().json.chat_id,
    filename: imageInfo.filename,
    subfolder: imageInfo.subfolder || '',
    type: imageInfo.type || 'output'
  }
}];

const raw = String($json?.message?.content || '').trim();

if (!raw) {
  throw new Error('Ollama no devolvió la clasificación.');
}

let parsed;

try {
  parsed = JSON.parse(raw);
} catch (error) {
  throw new Error('Ollama no devolvió JSON válido: ' + raw);
}

let tipo = String(parsed.tipo_sujeto || '')
  .toLowerCase()
  .trim();

const aliases = {
  persona: 'persona',
  personas: 'persona',
  person: 'persona',
  people: 'persona',
  humano: 'persona',
  humana: 'persona',

  animal: 'animal',
  animales: 'animal',
  cat: 'animal',
  dog: 'animal',
  gato: 'animal',
  perro: 'animal',

  objeto: 'objeto',
  object: 'objeto',
  artifact: 'objeto',
  artefacto: 'objeto',
  maquina: 'objeto',
  máquina: 'objeto',
  vehiculo: 'objeto',
  vehículo: 'objeto',

  mixto: 'mixto',
  mixed: 'mixto'
};

tipo = aliases[tipo] || 'mixto';

return [{
  json: {
    ...$json,
    tipo_sujeto: tipo,
    clasificacion_ollama: parsed
  }
}];

const items = $input.all();

return items.map(item => ({
  ...item,
  json: {
    ...item.json,
    positive_base: "Create a highly exaggerated hand-drawn caricature illustration based only on the person or people visible in the supplied reference image.

Use exactly the same number of people as in the reference image. Do not add, remove, duplicate, replace or invent anyone.

Preserve each person's recognizability, facial structure, hairstyle, expression, clothing, pose, head orientation, gaze, accessories and visible hand placement.

Exaggerate oversized expressive eyes, a very large cheerful smile and teeth, rounded or stretched cheeks, expressive eyebrows, enlarged head proportions, ears when appropriate and playful humorous facial proportions.

Make the result unmistakably a humorous caricature, not a realistic portrait, fashion illustration or elegant portrait drawing.

Style: monochrome blue ballpoint pen caricature drawing, visible rough construction lines, loose hand-drawn strokes, hatching, crosshatching, lively expressive linework and professional caricature artist quality.

Composition: one unified illustration, closely framed upper-body portrait, noticeably enlarged head and slightly smaller body, balanced composition and no photographic elements.

Background: plain warm cream background with subtle paper texture only. The cream background must fill the whole canvas.

Do not depict a notebook, sketchbook, journal page, spiral binding, punched holes, perforations, dotted paper, grid paper, ruled paper, visible sheet, page edge or border.

Render every visible detail only in blue ink and cream background. Do not use any other colors in the eyes, skin, hair, clothing or accessories.

Do not include text, letters, numbers, captions, labels, names, logos, signatures or watermarks."
  }
}));

const items = $input.all();

return items.map(item => ({
  ...item,
  json: {
    ...item.json,
    negative_prompt: "realistic portrait, refined portrait, elegant portrait, fashion illustration, portrait painting, painterly illustration, realistic proportions, normal-sized head, small eyes, restrained expression, photorealistic, realistic skin tones, full color, multicolor, colored eyes, green eyes, yellow details, red details, watercolor, digital painting, smooth vector art, notebook, sketchbook, spiral binding, punched holes, dotted paper, grid paper, ruled paper, page edge, page border, text, letters, numbers, logo, signature, watermark"
  }
}));

const items = $input.all();

return items.map(item => ({
  ...item,
  json: {
    ...item.json,
    negative_prompt: `realistic wildlife drawing, normal animal sketch, plain animal illustration, photographic animal, zoological illustration, stiff realistic anatomy, expressionless animal, anthropomorphic animal, humanoid animal, human torso, human chest, human shoulders, human arms, human hands, human fingers, bipedal stance, mascot, furry character, person with animal head, human clothing, notebook, sketchbook, spiral binding, punched holes, dotted paper, grid paper, page border, text, logo, signature, watermark`
  }
}));

const items = $input.all();

return items.map(item => ({
  ...item,
  json: {
    ...item.json,
    negative_prompt: `normal technical drawing, realistic object sketch, museum catalog illustration, engineering diagram, flat realistic proportions, neutral perspective, stiff composition, excessive empty space, oversized pedestal, oversized table, display plinth, human face, eyes on object, mouth on object, teeth on object, human hands, human body, humanoid object, mascot, cartoon character, invented components, invented labels, invented text, full color, multicolor, notebook, sketchbook, spiral binding, punched holes, dotted paper, grid paper, page edge, page border, logo, signature, watermark`
  }
}));

const items = $input.all();

return items.map(item => ({
  ...item,
  json: {
    ...item.json,
    negative_prompt: `added subject, removed subject, duplicated subject, replaced subject, separate panels, collage, split screen, disconnected composition, pasted character, realistic portrait, realistic proportions, expressionless person, anthropomorphic animal, humanoid animal, human torso on animal, human arms on animal, human hands on animal, human clothing on animal, person with animal head, furry character, mascot, human face on object, eyes on object, mouth on object, teeth on object, humanoid object, smiling machine, invented components, invented accessories, invented text, incorrect relative scale, altered positions, excessive empty space, oversized pedestal, oversized table, realistic technical drawing, museum catalog illustration, full color, multicolor, colored eyes, realistic skin tones, notebook, sketchbook, spiral binding, punched holes, dotted paper, grid paper, page edge, page border, text, logo, signature, watermark`
  }
}));

const items = $input.all();

return items.map(item => ({
  ...item,
  json: {
    ...item.json,
    local_settings: {
      seed_mode: 'random',
      fixed_seed: 987654321,
      steps: 4,
      cfg: 1.0,
      denoise: 1.0,
      lora_strength: 1.0,
      model_shift: 3.1,
      use_negative_prompt: true
    }
  }
}));
